#include "diagengine/DiagnosticExplainer.h"
namespace diagengine { DiagnosticExplanation DiagnosticExplainer::explain(const cminus::Diagnostic& d,const std::string&)const{DiagnosticExplanation e;e.code=d.code;e.line=d.range.line;e.column=d.range.column;e.message=d.message;e.lexeme="";if(d.code=="LEX_MALFORMED_NUMBER"){e.explanation="A numeric literal absorbed characters that cannot belong to the same token.";e.fixes.push_back(FixHint{"split number and identifier","12 abc",0.8});}else if(d.code=="LEX_UNTERMINATED_COMMENT"){e.explanation="A block comment reached end of file before */.";e.fixes.push_back(FixHint{"close block comment","*/",0.95});}else if(d.code=="LEX_ISOLATED_BANG"){e.explanation="A teaching dialect may reserve ! for != rather than a standalone operator.";e.fixes.push_back(FixHint{"complete inequality","!=",0.75});}else if(d.code=="LEX_INVALID_OPERATOR_SEQUENCE"){e.explanation="The operator sequence cannot be tokenized as a valid intended operator.";e.fixes.push_back(FixHint{"use logical and","&&",0.7});}else{e.explanation="The character sequence is not accepted by the lexer rules.";e.fixes.push_back(FixHint{"remove or replace token","",0.6});}return e;} }
